define i8 @urem_without_assume(i8 %arg, i8 %arg2) {
  %x = urem i8 %arg, %arg2
  %add = add i8 %x, 1
  %out = urem i8 %add, %arg2
  ret i8 %out
}

define i8 @urem_without_assume_a_var(i8 %arg, i8 %arg2, i8 %a) {
  %x = urem i8 %arg, %arg2
  %add = add i8 %x, %a
  %out = urem i8 %add, %arg2
  ret i8 %out
}
